import { Animation } from './Animation';
import { AnimResults, HasAudio, AnimQuery } from './Classes';


let SemverUtils = require('semver-utils');


/**
 * @typedef jibo.animdb#SemVer
 * @description interface
 * @property semver {string} Example '1.0.4-alpha.1'
 * @property version {string} Example '1.0.4'
 * @property major {number} Example '1'
 * @property minor {number} Example '0'
 * @property patch {number} Example '4'
 * @property [release] {string} Example 'alpha.1'
 * @intdocs
 */
export interface SemVer {
    semver: string;     // Example '1.0.4-alpha.1'
    version: string;    // Example '1.0.4'
    major: number;      // Example '1'
    minor: number;      // Example '0'
    patch: number;      // Example '4'
    release?: string;   // Example 'alpha.1'
}


/**
 * @class Utils
 * @memberof jibo.animdb
 * @intdocs
 */
export class Utils {

    /**
     * Returns input or default value if input is falsey or empty
     * @method jibo.animdb.Utils#parseString
     * @static
     * @param {string} input
     * @param {string} defaultVal
     * @returns {string}
     */
    static parseString(input: any, defaultVal: string) {
        if (!input || !(input.length)) {
            return defaultVal;
        }
        return input;
    }

    /**
     * Returns input or default value if input is falsey or empty
     * @method jibo.animdb.Utils#parseNumber
     * @static
     * @param {string} input
     * @param {number} defaultVal
     * @returns {string}
     */
    static parseNumber(input: any, defaultVal: number) {
        if (typeof input === 'number') {
            return input;
        }

        if (!input || !(input.length)) {
            return defaultVal;
        }

        try {
            let num = parseFloat(input);
            return num;
        }
        catch(e) {
            return defaultVal;
        }
    }

    /**
     * Parses input string to SemVer object
     * @method jibo.animdb.Utils#parseSemVer
     * @static
     * @param {string} input
     * @returns {jibo.animdb#SemVer}
     */
    static parseSemVer(input: string): SemVer {
        let parse = SemverUtils.parse(input);
        return {
            semver: parse.semver,
            version: parse.version,
            major: parseInt(parse.major),
            minor: parseInt(parse.minor),
            patch: parseInt(parse.patch),
            release: parse.release
        };
    }

    /**
     * Retrieves all animations from a list that match a certain
     * duration criteria
     * @method jibo.animdb.Utils#getAnimationsByQuery
     * @static
     * @param {jibo.animdb.Animation[]} animations Input animation collection
     * @param {jibo.animdb.AnimResults} interimResults
     * @param {jibo.animdb#AnimQuery} [query] Selection criteria
     */
    static getAnimationsByQuery(animations: Animation[], interimResults: AnimResults, query: AnimQuery) {
        animations.forEach( anim => {
            if (Utils.audioMatch(anim, query.hasAudio) &&
                Utils.catMatch(anim, query.includeCat, query.includeSomeCat, query.excludeCat) &&
                Utils.metaMatch(anim, query.includeMeta, query.includeSomeMeta, query.excludeMeta)) {
                Utils.addIfDurationMatch(anim, query.duration, query.durationError, interimResults);
            }
        });
    }

    /**
     * Checks if animation matches audio requirement
     * @method jibo.animdb.Utils#audioMatch
     * @static
     * @param {jibo.animdb.Animation} animation
     * @param {jibo.animdb#HasAudio} shouldHaveAudio
     * @returns {boolean}
     */
    static audioMatch(animation: Animation, shouldHaveAudio: HasAudio): boolean {
        return  (shouldHaveAudio === HasAudio.DONT_CARE) ||
            (shouldHaveAudio === HasAudio.YES && animation.meta.hasAudio) ||
            (shouldHaveAudio === HasAudio.NO && !animation.meta.hasAudio);
    }

    /**
     * Checks if animation matches category criteria
     * @method jibo.animdb.Utils#catMatch
     * @static
     * @param {jibo.animdb.Animation} animation
     * @param {string[]} allOfCat -- List of categories that the animation must be a part of
     * @param {string[]} someOfCat -- List of categories that the animation should be a part of at least one of
     * @param {string[]} noneOfCat -- List of categories that the animation must not be a part of
     * @returns {boolean}
     */
    static catMatch(animation: Animation, allOfCat: string[], someOfCat: string[], noneOfCat: string[]): boolean {
        const categories = animation.meta.categories;
        const allOfMatch = (allOfCat.length > 0) ? allOfCat.every(cat => categories.indexOf(cat) !== -1) : true;
        const someOfMatch = (someOfCat.length > 0) ? someOfCat.some(cat => categories.indexOf(cat) !== -1) : true;
        const noneOfMatch = (noneOfCat.length > 0) ? noneOfCat.every(cat => categories.indexOf(cat) === -1) : true;
        return (allOfMatch && someOfMatch && noneOfMatch);
    }

    /**
     * Checks if animation matches meta tag criteria
     * @method jibo.animdb.Utils#metaMatch
     * @static
     * @param {jibo.animdb.Animation} animation
     * @param {string[]} allOfMeta -- List of meta that the animation must contain
     * @param {string[]} someOfMeta -- List of meta that the animation must contain at least one of
     * @param {string[]} noneOfMeta -- List of meta that the animation must not contain
     * @returns {boolean}
     */
    static metaMatch(animation: Animation, allOfMeta: string[], someOfMeta: string[], noneOfMeta: string[]): boolean {
        const metas = animation.meta.metaTerms;
        const allOfMatch = (allOfMeta.length > 0) ? allOfMeta.every(meta => metas.indexOf(meta) !== -1) : true;
        const someOfMatch = (someOfMeta.length > 0) ? someOfMeta.some(meta => metas.indexOf(meta) !== -1) : true;
        const noneOfMatch = (noneOfMeta.length > 0) ? noneOfMeta.every(meta => metas.indexOf(meta) === -1) : true;
        return (allOfMatch && someOfMatch && noneOfMatch);
    }

    /**
     * Adds animation to result if duration matches bounds
     * @method jibo.animdb.Utils#addIfDurationMatch
     * @static
     * @param {jibo.animdb.Animation} animation
     * @param {number} duration
     * @param {number} durationError
     * @param {jibo.animdb.AnimResults} res
     */
    static addIfDurationMatch(animation: Animation, duration: number, durationError: number, res: AnimResults): void {
        if (duration === -1) {
            res.matching.push(animation);
        }
        else {
            let dist = Utils.distanceFromRange(duration, animation.meta.durationRange);
            if (dist === 0) {
                res.matching.push(animation);
            }
            else if (dist <= durationError) {
                res.nonMatching.push(animation);
            }
        }
    }

    /**
     * Takes a number and limits it by this range.
     * If min then return min bound, if higher then return max bound
     * @method jibo.animdb.Utils#limitToRange
     * @static
     * @param {number} num
     * @param {number[]} range [min, max]
     * @returns {number}
     */
    static limitToRange(num: number, range: number[]) {
        if (num < range[0]) {
            return range[0];
        }
        else if (num > range[1]) {
            return range[1];
        }
        else {
            return num;
        }
    }

    /**
     * Reports how far a number is from being within this range
     * Returns 0 if it is contained in range
     * @method jibo.animdb.Utils#distanceFromRange
     * @static
     * @param {number} num
     * @param {number[]} range [min, max]
     * @returns {number}
     */
    static distanceFromRange(num: number, range: number[]) {
        if (num < range[0]) {
            return range[0] - num;
        }
        else if (num > range[1]) {
            return num - range[1];
        }
        else {
            return 0;
        }
    }
}
